    currentText = ("dat waren alle vragen van deze triva game, goed gedaan\n je kan op enter drukken om opnieuw te spelen");
    DisplayText();
    Console.ReadLine();
    Menu();

    void AskQuestion()
    {
        Random rnd = new Random();
        int vraagIndex = rnd.Next(0, vragenlijst.Count);
        currentText = (vragenlijst[vraagIndex]);
        for(int i =0; i < topUi.Length; i++ )
        {
            Console.WriteLine(topUi[i]);
        }
        
        DisplayText();
        Console.WriteLine($"\n\nuser: {username}\t\t\tremaining lives: {tries}");
        string antwoord = "a";
        while (antwoord.Length <= 1)
        {
            antwoord = Console.ReadLine()!.Trim();
            if (antwoord.Length <= 1)
            {
                currentText = "sorry that awnser is too short\n";
                DisplayText();
            }
        }
        if (antwoord.ToLower().Equals(antwoordlijst[vraagIndex].ToLower()))
        {
            Console.Clear();
            for (int i = 0; i < good.Length; i++)
            {
                Console.WriteLine(good[i]);
            }
            Console.WriteLine("dat is juist");
            Console.Beep(600, 50);
            Console.Beep(800, 50);
            Console.Beep(1050, 50);
            Thread.Sleep(1000);
        }
        else
        {
            Console.Clear();
            for (int i = 0; i < bad.Length; i++)
            {
                Console.WriteLine(bad[i]);
            }
            Console.WriteLine("dat is fout");
            tries --;
            Console.Beep(1000, 50);
            Console.Beep(800,50);
            Console.Beep(600, 50);
            Thread.Sleep(1000);
        }
        vragenlijst.RemoveAt(vraagIndex);
        antwoordlijst.RemoveAt(vraagIndex);
    }
}

